        )

mentor = frappe.db.get_value("Mentor", {"user": frappe.session.user}, "name")

if not mentor:
    pass
else:
    interns = frappe.get_all(
        "Intern",
        filters={"mentor": mentor},
        pluck="name"
    )

    if doc.intern not in interns:
        frappe.throw("You are not allowed to access this log.")

if frappe.session.user == "Administrator":
    conditions = ""  # Admin sees everything

else:
    mentor = frappe.db.get_value("Mentor", {"user": frappe.session.user}, "name")

    if mentor:
        assigned_interns = frappe.db.get_all(
            "Intern",
            filters={"mentor": mentor},
            pluck="name"
        )

        if not assigned_interns:
            conditions = "1=0"  # Mentor exists but has no interns
        else:
            intern_list = ", ".join([frappe.db.escape(i) for i in assigned_interns])
            conditions = f"`tabDaily Work Logs`.intern in ({intern_list})"

    else:
        conditions = ""  # Logged-in user is not a mentor (e.g. Intern role)

# frappe.throw("SCRIPT RUNNING")
# condition = ""
# condition

if doc.date:
    log_date = frappe.utils.getdate(doc.date)
    today_date = frappe.utils.getdate(frappe.utils.today())
    
    if log_date < today_date:
        doc.is_late = 1
    else:
        doc.is_late = 0

if not doc.intern or not doc.date:
    frappe.throw("Intern and Date are required.")

existing = frappe.db.exists("Intern Attendance", {
    "intern": doc.intern,
    "date": doc.date,
    "name": ["!=", doc.name]
})

if existing:
    frappe.throw(
        f"Attendance for {doc.intern} on {doc.date} is already marked."
    )

doc.marked_by = frappe.session.user

intern_name = doc.intern

total = frappe.db.count("Intern Attendance", {
    "intern": intern_name
})

present = frappe.db.count("Intern Attendance", {
    "intern": intern_name,
    "status": "Present"
})

percentage = round((present / total) * 100, 2) if total > 0 else 0

frappe.db.set_value("Intern", intern_name, {
    "total_working_days": total,
    "present_days": present,
    "attendance_percentage": percentage,
    "low_attendance": 1 if percentage < 75 else 0
})
